def calculate(s):
    def helper(it):
        stack = []
        num = 0
        op = '+'
        while it < len(s):
            c = s[it]
            if c.isdigit():
                num = num * 10 + int(c)
            if c == '(':
                it, num = helper(it + 1)
            if (not c.isdigit() and c != ' ') or it == len(s) - 1:
                if op == '+': stack.append(num)
                elif op == '-': stack.append(-num)
                elif op == '*': stack.append(stack.pop() * num)
                elif op == '/': stack.append(int(stack.pop() / num))
                op = c; num = 0
                if c == ')': return it, sum(stack)
            it += 1
        return it, sum(stack)
    return helper(0)[1]

